/*
 * YANG Data Structures and NETCONF Message Handling for IoT
 * Implements YANG-defined data models and NETCONF protocol operations
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

/* Maximum sizes for buffers */
#define MAX_CAPABILITIES 64
#define MAX_DEVICES 256
#define MAX_XML_SIZE 4096

/* NETCONF namespaces */
const char* NETCONF_NS = "urn:ietf:params:xml:ns:netconf:base:1.0";
const char* IOT_SENSOR_NS = "http://example.com/iot-sensor";

/* ====================================================================
 * YANG Data Structure Definitions
 * Following YANG model: iot-temperature-sensor
 * ==================================================================== */

/* YANG leaf: device-id (string) */
typedef struct {
    char device_id[64];
} YangLeafString;

/* YANG leaf: sampling-interval (uint32, default 60) */
typedef struct {
    unsigned int value;
    unsigned int default_value;
    bool is_set;
} YangLeafUint32;

/* YANG leaf: reporting-threshold (decimal64) */
typedef struct {
    double value;
    double default_value;
    bool is_set;
} YangLeafDecimal64;

/* YANG container: sensor-config (configuration data) */
typedef struct {
    YangLeafString device_id;
    YangLeafUint32 sampling_interval;
    YangLeafDecimal64 reporting_threshold;
} YangContainerSensorConfig;

/* YANG container: sensor-state (operational state, config=false) */
typedef struct {
    double temperature;
    unsigned int battery_level;
    bool is_valid;
} YangContainerSensorState;

/* Complete IoT device YANG model */
typedef struct {
    YangContainerSensorConfig config;
    YangContainerSensorState state;
    char yang_model[128];
} IoTSensorDevice;

/* ====================================================================
 * NETCONF Message Generation Functions
 * ==================================================================== */

/* Generate NETCONF hello message (client capabilities) */
char* netconf_generate_hello(char* buffer, size_t buffer_size) {
    snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<hello xmlns=\"%s\">\n"
        "  <capabilities>\n"
        "    <capability>urn:ietf:params:netconf:base:1.1</capability>\n"
        "    <capability>urn:ietf:params:netconf:capability:candidate:1.0</capability>\n"
        "    <capability>urn:ietf:params:netconf:capability:validated:1.0</capability>\n"
        "    <capability>urn:ietf:params:netconf:capability:rollback-on-error:1.0</capability>\n"
        "    <capability>%s</capability>\n"
        "  </capabilities>\n"
        "</hello>",
        NETCONF_NS, IOT_SENSOR_NS);
    return buffer;
}

/* Generate NETCONF get-config RPC */
char* netconf_generate_get_config(char* buffer, size_t buffer_size,
                                   const char* source, const char* filter) {
    int offset = snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<rpc message-id=\"101\" xmlns=\"%s\">\n"
        "  <get-config>\n"
        "    <source>\n"
        "      <%s/>\n"
        "    </source>\n",
        NETCONF_NS, source);

    if (filter && strlen(filter) > 0) {
        offset += snprintf(buffer + offset, buffer_size - offset,
            "    <filter type=\"subtree\">\n%s\n    </filter>\n", filter);
    }

    offset += snprintf(buffer + offset, buffer_size - offset,
        "  </get-config>\n"
        "</rpc>");

    return buffer;
}

/* Generate NETCONF edit-config RPC with YANG data */
char* netconf_generate_edit_config(char* buffer, size_t buffer_size,
                                     const char* target,
                                     const char* yang_config) {
    snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<rpc message-id=\"102\" xmlns=\"%s\">\n"
        "  <edit-config>\n"
        "    <target>\n"
        "      <%s/>\n"
        "    </target>\n"
        "    <config>\n%s\n    </config>\n"
        "    <error-option>rollback-on-error</error-option>\n"
        "  </edit-config>\n"
        "</rpc>",
        NETCONF_NS, target, yang_config);
    return buffer;
}

/* Generate NETCONF get RPC for operational state */
char* netconf_generate_get(char* buffer, size_t buffer_size, const char* filter) {
    if (filter && strlen(filter) > 0) {
        snprintf(buffer, buffer_size,
            "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
            "<rpc message-id=\"103\" xmlns=\"%s\">\n"
            "  <get>\n"
            "    <filter type=\"subtree\">\n%s\n    </filter>\n"
            "  </get>\n"
            "</rpc>",
            NETCONF_NS, filter);
    } else {
        snprintf(buffer, buffer_size,
            "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
            "<rpc message-id=\"103\" xmlns=\"%s\">\n"
            "  <get/>\n"
            "</rpc>",
            NETCONF_NS);
    }
    return buffer;
}

/* Generate NETCONF lock RPC */
char* netconf_generate_lock(char* buffer, size_t buffer_size, const char* target) {
    snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<rpc message-id=\"104\" xmlns=\"%s\">\n"
        "  <lock>\n"
        "    <target>\n"
        "      <%s/>\n"
        "    </target>\n"
        "  </lock>\n"
        "</rpc>",
        NETCONF_NS, target);
    return buffer;
}

/* Generate NETCONF unlock RPC */
char* netconf_generate_unlock(char* buffer, size_t buffer_size, const char* target) {
    snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<rpc message-id=\"105\" xmlns=\"%s\">\n"
        "  <unlock>\n"
        "    <target>\n"
        "      <%s/>\n"
        "    </target>\n"
        "  </unlock>\n"
        "</rpc>",
        NETCONF_NS, target);
    return buffer;
}

/* Generate NETCONF commit RPC */
char* netconf_generate_commit(char* buffer, size_t buffer_size) {
    snprintf(buffer, buffer_size,
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n"
        "<rpc message-id=\"106\" xmlns=\"%s\">\n"
        "  <commit/>\n"
        "</rpc>",
        NETCONF_NS);
    return buffer;
}

/* ====================================================================
 * YANG Configuration Building Functions
 * ==================================================================== */

/* Initialize sensor configuration with defaults (per YANG model) */
void yang_init_sensor_config(YangContainerSensorConfig* config) {
    strcpy(config->device_id.device_id, "");
    config->sampling_interval.value = 60;  /* Default from YANG */
    config->sampling_interval.default_value = 60;
    config->sampling_interval.is_set = false;
    config->reporting_threshold.value = 0.0;
    config->reporting_threshold.default_value = 0.0;
    config->reporting_threshold.is_set = false;
}

/* Build YANG XML configuration from sensor config structure */
char* yang_build_sensor_config_xml(char* buffer, size_t buffer_size,
                                     const YangContainerSensorConfig* config) {
    int offset = snprintf(buffer, buffer_size,
        "<sensor-config xmlns=\"%s\">\n", IOT_SENSOR_NS);

    if (strlen(config->device_id.device_id) > 0) {
        offset += snprintf(buffer + offset, buffer_size - offset,
            "  <device-id>%s</device-id>\n", config->device_id.device_id);
    }

    if (config->sampling_interval.is_set) {
        offset += snprintf(buffer + offset, buffer_size - offset,
            "  <sampling-interval>%u</sampling-interval>\n",
            config->sampling_interval.value);
    } else {
        offset += snprintf(buffer + offset, buffer_size - offset,
            "  <sampling-interval>%u</sampling-interval>\n",
            config->sampling_interval.default_value);
    }

    if (config->reporting_threshold.is_set) {
        offset += snprintf(buffer + offset, buffer_size - offset,
            "  <reporting-threshold>%.2f</reporting-threshold>\n",
            config->reporting_threshold.value);
    }

    offset += snprintf(buffer + offset, buffer_size - offset,
        "</sensor-config>");

    return buffer;
}

/* Build filter XML for sensor state (config=false, read-only) */
char* yang_build_state_filter_xml(char* buffer, size_t buffer_size) {
    snprintf(buffer, buffer_size,
        "<sensor-state xmlns=\"%s\">\n"
        "  <temperature/>\n"
        "  <battery-level/>\n"
        "</sensor-state>",
        IOT_SENSOR_NS);
    return buffer;
}

/* ====================================================================
 * NETCONF Operations Implementation
 * ==================================================================== */

typedef enum {
    NETCONF_OK,
    NETCONF_ERROR,
    NETCONF_ERR_TOO_BIG,
    NETCONF_ERR_MISSING_ATTR,
    NETCONF_ERR_BAD_ATTR,
    NETCONF_ERR_UNKNOWN_ATTR,
    NETCONF_ERR_BAD_ELEMENT,
    NETCONF_ERR_UNKNOWN_ELEMENT,
    NETCONF_ERR_UNKNOWN_NAMESPACE,
    NETCONF_ERR_ACCESS_DENIED,
    NETCONF_ERR_LOCK_DENIED,
    NETCONF_ERR_RESOURCE_DENIED,
    NETCONF_ERR_ROLLBACK_FAILED
} NetconfErrorType;

/* Simulated NETCONF session */
typedef struct {
    int socket_fd;
    char session_id[32];
    bool is_locked;
    char* capabilities[MAX_CAPABILITIES];
    int cap_count;
} NetconfSession;

/* Process NETCONF response and extract ok or error */
NetconfErrorType netconf_process_response(const char* response) {
    /* Simplified response parsing - check for <ok> or <rpc-error> */
    if (strstr(response, "<ok/>") != NULL || strstr(response, "<ok>") != NULL) {
        printf("[NETCONF] Operation successful\n");
        return NETCONF_OK;
    }

    if (strstr(response, "<rpc-error>") != NULL) {
        printf("[NETCONF] Operation failed with error\n");
        return NETCONF_ERROR;
    }

    return NETCONF_OK;
}

/* Complete configuration workflow with transaction support */
bool netconf_configure_device(NetconfSession* session,
                               IoTSensorDevice* device) {
    char xml_buffer[MAX_XML_SIZE];
    char yang_config[MAX_XML_SIZE];

    /* Step 1: Lock candidate datastore */
    netconf_generate_lock(xml_buffer, MAX_XML_SIZE, "candidate");
    printf("[NETCONF] Locking candidate datastore...\n");
    printf("Request: %s\n", xml_buffer);
    /* In real implementation: send over socket, receive response */

    /* Step 2: Build YANG configuration */
    yang_build_sensor_config_xml(yang_config, MAX_XML_SIZE, &device->config);

    /* Step 3: Edit configuration */
    netconf_generate_edit_config(xml_buffer, MAX_XML_SIZE, "candidate", yang_config);
    printf("[NETCONF] Editing configuration...\n");
    printf("Config: %s\n", yang_config);
    /* In real implementation: send over socket, receive response */

    /* Step 4: Commit configuration */
    netconf_generate_commit(xml_buffer, MAX_XML_SIZE);
    printf("[NETCONF] Committing to running...\n");
    /* In real implementation: send over socket, receive response */

    /* Step 5: Unlock candidate datastore */
    netconf_generate_unlock(xml_buffer, MAX_XML_SIZE, "candidate");
    printf("[NETCONF] Unlocking candidate datastore\n");
    /* In real implementation: send over socket, receive response */

    return true;
}

/* Monitor device operational state */
bool netconf_monitor_device(NetconfSession* session, IoTSensorDevice* device) {
    char xml_buffer[MAX_XML_SIZE];
    char state_filter[MAX_XML_SIZE];

    /* Build filter for sensor state data */
    yang_build_state_filter_xml(state_filter, MAX_XML_SIZE);

    /* Generate get RPC with filter */
    netconf_generate_get(xml_buffer, MAX_XML_SIZE, state_filter);
