/* ====================================================================
 * Main - Demonstration
 * ==================================================================== */

int main() {
    char xml_buffer[MAX_XML_SIZE];
    IoTSensorDevice sensor;

    printf("=== NETCONF-YANG IoT Device Management Demo ===\n\n");

    /* Initialize sensor configuration */
    yang_init_sensor_config(&sensor.config);

    /* Set configuration values */
    strcpy(sensor.config.device_id.device_id, "temp-sensor-042");
    sensor.config.sampling_interval.value = 30;
    sensor.config.sampling_interval.is_set = true;
    sensor.config.reporting_threshold.value = 25.0;
    sensor.config.reporting_threshold.is_set = true;

    /* Generate and display NETCONF hello message */
    printf("--- NETCONF Hello Message ---\n");
    netconf_generate_hello(xml_buffer, MAX_XML_SIZE);
    printf("%s\n\n", xml_buffer);

    /* Generate and display get-config RPC */
    printf("--- NETCONF get-config RPC ---\n");
    char filter[] = "<sensor-config xmlns=\"http://example.com/iot-sensor\"/>";
    netconf_generate_get_config(xml_buffer, MAX_XML_SIZE, "running", filter);
    printf("%s\n\n", xml_buffer);

    /* Generate and display edit-config RPC */
    printf("--- NETCONF edit-config RPC ---\n");
    char yang_config[MAX_XML_SIZE];
    yang_build_sensor_config_xml(yang_config, MAX_XML_SIZE, &sensor.config);
    netconf_generate_edit_config(xml_buffer, MAX_XML_SIZE, "candidate", yang_config);
    printf("%s\n\n", xml_buffer);

    /* Generate and display get RPC for state */
    printf("--- NETCONF get RPC (Operational State) ---\n");
    char state_filter[MAX_XML_SIZE];
    yang_build_state_filter_xml(state_filter, MAX_XML_SIZE);
    netconf_generate_get(xml_buffer, MAX_XML_SIZE, state_filter);
    printf("%s\n\n", xml_buffer);

    /* Demonstrate complete workflow */
    printf("--- Configuration Workflow ---\n");
    NetconfSession session = {0};
    netconf_configure_device(&session, &sensor);

    printf("\n--- Monitoring Workflow ---\n");
    netconf_monitor_device(&session, &sensor);

    printf("\n=== Demo Complete ===\n");

    return 0;
}
